@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings
@using sv_0558d4757ab84d58ac6fe1e457f8bf14.Models

<div class="settings-section">
    <h3>Profile Settings</h3>

    @if (ShowSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Profile saved successfully!
            <button type="button" class="btn-close" @onclick="() => ShowSuccess = false"></button>
        </div>
    }

    <div class="profile-form">
        <div class="avatar-preview mb-4">
            <img src="@AvatarUrl" alt="Avatar" class="rounded-circle avatar-img" />
            <div class="mt-2">
                <label class="form-label fw-semibold">Avatar URL</label>
                <input type="text" class="form-control" @bind="AvatarUrl" />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="DisplayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="Email" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="Bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        ShowSuccess = true;
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        ShowSuccess = false;
    }
}

@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings
@using sv_0558d4757ab84d58ac6fe1e457f8bf14.Models

<div class="settings-section">
    <h3>Notification Preferences</h3>

    @if (ShowSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Preferences saved successfully!
            <button type="button" class="btn-close" @onclick="() => ShowSuccess = false"></button>
        </div>
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
            <label class="form-check-label" for="emailNotif">
                <strong>Email Notifications</strong>
                <div class="text-muted small">Receive notifications via email</div>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
            <label class="form-check-label" for="pushNotif">
                <strong>Push Notifications</strong>
                <div class="text-muted small">Receive push notifications in your browser</div>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a summary of activity each week</div>
            </label>
        </div>
    </div>

    <h5>Muted Channels</h5>
    <p class="text-muted small">Select channels you want to mute</p>
    <div class="channel-list mb-4">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="(e) => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel
                </label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
    [Parameter] public List<string> AllChannels { get; set; } = [];

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        ShowSuccess = true;
    }
}

@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary mb-3" @onclick="ToggleExpanded">
        @(IsExpanded ? "▼" : "▶") Change Password
    </button>

    @if (IsExpanded)
    {
        <div class="card card-body">
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger">@ErrorMessage</div>
            }
            @if (ShowSuccess)
            {
                <div class="alert alert-success">Password updated successfully!</div>
            }

            <div class="mb-3">
                <label class="form-label fw-semibold">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@IsSubmitting">
                @(IsSubmitting ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private bool ShowSuccess;
    private bool IsSubmitting;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            ErrorMessage = "Current password is required.";
            return;
        }
        if (NewPassword.Length < 6)
        {
            ErrorMessage = "New password must be at least 6 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New passwords do not match.";
            return;
        }

        IsSubmitting = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsSubmitting = false;
        ShowSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
    }
}

@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings

<!-- Confirmation Dialog -->
@if (ShowDialog)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@SessionDevice</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool ShowDialog { get; set; }
    [Parameter] public string SessionDevice { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings
@using sv_0558d4757ab84d58ac6fe1e457f8bf14.Models

<div class="settings-section">
    <h3>Security Settings</h3>

    @if (Security is not null)
    {
        <!-- Change Password -->
        <div class="mb-4">
            <ChangePasswordPanel OnChangePassword="OnChangePassword" />
            @if (Security.LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2">
                    Last changed: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="mb-4">
            <h5>Two-Factor Authentication</h5>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@TwoFactorEnabled"
                           @onchange="Toggle2FA" />
                    <label class="form-check-label" for="twoFactor">Enable 2FA</label>
                </div>
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="mb-4">
            <h5>Active Sessions</h5>
            <div class="table-responsive">
                <table class="table table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Security.Sessions)
                        {
                            var isCurrent = session.Id == CurrentSessionId;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-2">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
