<div class="change-password-panel">
    <button class="btn btn-outline-secondary mb-3" @onclick="ToggleExpanded">
        @(IsExpanded ? "▼" : "▶") Change Password
    </button>

    @if (IsExpanded)
    {
        <div class="card card-body">
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger">@ErrorMessage</div>
            }
            @if (ShowSuccess)
            {
                <div class="alert alert-success">Password updated successfully!</div>
            }

            <div class="mb-3">
                <label class="form-label fw-semibold">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@IsSubmitting">
                @(IsSubmitting ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private bool ShowSuccess;
    private bool IsSubmitting;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            ErrorMessage = "Current password is required.";
            return;
        }
        if (NewPassword.Length < 6)
        {
            ErrorMessage = "New password must be at least 6 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New passwords do not match.";
            return;
        }

        IsSubmitting = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsSubmitting = false;
        ShowSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
    }
}
