@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings
@using sv_0558d4757ab84d58ac6fe1e457f8bf14.Models

<div class="appearance-preview card">
    <div class="card-header">
        <strong>Live Preview</strong>
    </div>
    <div class="card-body preview-body @ThemeClass @FontClass @(CompactMode ? "compact" : "")">
        <div class="preview-header">
            <h6>Sample Header</h6>
            <span class="badge bg-primary">Badge</span>
        </div>
        <p class="preview-text">
            This is how your content will look with the selected settings.
            The quick brown fox jumps over the lazy dog.
        </p>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm">Primary</button>
            <button class="btn btn-outline-secondary btn-sm">Secondary</button>
        </div>
        <div class="preview-list mt-2">
            <div class="preview-list-item">📧 Inbox (3 new)</div>
            <div class="preview-list-item">📋 Tasks (12 pending)</div>
            <div class="preview-list-item">💬 Messages (5 unread)</div>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public bool CompactMode { get; set; }

    private string ThemeClass => Theme.ToLowerInvariant() switch
    {
        "dark" => "preview-dark",
        "system" => "preview-system",
        _ => "preview-light"
    };

    private string FontClass => FontSize.ToLowerInvariant() switch
    {
        "small" => "preview-font-sm",
        "large" => "preview-font-lg",
        _ => "preview-font-md"
    };
}

@namespace sv_0558d4757ab84d58ac6fe1e457f8bf14.Components.Pages.Settings
@using sv_0558d4757ab84d58ac6fe1e457f8bf14.Models

<div class="settings-section">
    <h3>Appearance Settings</h3>

    @if (ShowSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Appearance saved successfully!
            <button type="button" class="btn-close" @onclick="() => ShowSuccess = false"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <!-- Theme -->
            <div class="mb-4">
                <h5>Theme</h5>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                               value="@theme" checked="@(SelectedTheme == theme)"
                               @onchange="() => SelectedTheme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <h5>Font Size</h5>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"font-{size}")"
                               value="@size" checked="@(SelectedFontSize == size)"
                               @onchange="() => SelectedFontSize = size" />
                        <label class="form-check-label" for="@($"font-{size}")">@size</label>
                    </div>
                }
            </div>

            <!-- Language -->
            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" @bind="SelectedLanguage">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactModeEnabled" />
                    <label class="form-check-label" for="compactMode">
                        <strong>Compact Mode</strong>
                        <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
        </div>

        <div class="col-md-6">
            <AppearancePreview Theme="@SelectedTheme"
                               FontSize="@SelectedFontSize"
                               CompactMode="@CompactModeEnabled" />
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string SelectedTheme = "Light";
    private string SelectedFontSize = "Medium";
    private string SelectedLanguage = "English";
    private bool CompactModeEnabled;
    private bool ShowSuccess;
    private bool _initialized;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            SelectedTheme = Settings.Theme;
            SelectedFontSize = Settings.FontSize;
            SelectedLanguage = Settings.Language;
            CompactModeEnabled = Settings.CompactMode;
            _initialized = true;
        }
    }

    private async Task SaveAsync()
    {
        var updated = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactModeEnabled);
        await OnSave.InvokeAsync(updated);
        ShowSuccess = true;
    }
}

