    <div class="settings-content">
        @if (IsLoading)
        {
            <div class="d-flex justify-content-center p-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "Profile":
                    <ProfileSection Profile="@Profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@NotificationPrefs"
                                          AllChannels="@AllChannels"
                                          OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection Security="@Security"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@Appearance" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string ActiveSection = "Profile";
    private bool IsLoading = true;

    private UserProfile? Profile;
    private NotificationPrefs? NotificationPrefs;
    private SecuritySettings? Security;
    private AppearanceSettings? Appearance;
    private List<string> AllChannels = [];

    protected override async Task OnInitializedAsync()
    {
        AllChannels = MockSettingsService.GetAllChannels();
        await LoadAllDataAsync();
    }

    private async Task LoadAllDataAsync()
    {
        IsLoading = true;

        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        Profile = profileTask.Result;
        NotificationPrefs = notifTask.Result;
        Security = securityTask.Result;
        Appearance = appearanceTask.Result;

        IsLoading = false;
    }

    private void SetSection(string section)
    {
        ActiveSection = section;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        Profile = profile;
    }

    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        NotificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        Appearance = settings;
    }
}

