    color: #1e1e2e;
}

::deep .preview-dark .btn-primary {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

::deep .preview-dark .btn-outline-secondary {
    color: #a6adc8;
    border-color: #585b70;
}

::deep .preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

::deep .preview-font-sm {
    font-size: 0.8rem;
}

::deep .preview-font-md {
    font-size: 1rem;
}

::deep .preview-font-lg {
    font-size: 1.2rem;
}

::deep .compact {
    padding: 0.5rem !important;
}

::deep .compact .preview-list-item {
    padding: 0.15rem 0;
